import{_ as t,o as l,c as r,a2 as o}from"./chunks/framework.Pywvta2k.js";const _=JSON.parse('{"title":"外台秘要","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/02-魏晋隋唐/05-外台秘要（王焘）.md","filePath":"tcm-data/02-魏晋隋唐/05-外台秘要（王焘）.md","lastUpdated":1781084559000}'),e={name:"tcm-data/02-魏晋隋唐/05-外台秘要（王焘）.md"};function i(n,a,s,h,d,c){return l(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="外台秘要" tabindex="-1">外台秘要 <a class="header-anchor" href="#外台秘要" aria-label="Permalink to &quot;外台秘要&quot;">​</a></h1><blockquote><p>王焘（约670-755年），陕西郿县人 唐代大型医学百科全书 代表作：《外台秘要》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>成书</strong>：唐天宝十一年（752年）</li><li><strong>卷数</strong>：40卷</li><li><strong>规模</strong>：载方6800余首</li><li><strong>学术地位</strong>：与《千金方》并称为唐代医学双璧</li><li><strong>特点</strong>：每条皆注明出处——<strong>王焘是中医文献学的奠基人</strong></li></ul><h3 id="编纂方法" tabindex="-1">编纂方法 <a class="header-anchor" href="#编纂方法" aria-label="Permalink to &quot;编纂方法&quot;">​</a></h3><p>王焘在编书时有一个极其严谨的原则：<strong>每条引文都注明出处</strong>（来自哪本书、哪一篇）。这在古代医学文献中是极为罕见的。因此《外台秘要》成为了解唐以前医学文献的<strong>桥梁</strong>——很多已经失传的古医书，可以通过此书了解其内容。</p><hr><h2 id="二、核心内容" tabindex="-1">二、核心内容 <a class="header-anchor" href="#二、核心内容" aria-label="Permalink to &quot;二、核心内容&quot;">​</a></h2><h3 id="分类法" tabindex="-1">分类法 <a class="header-anchor" href="#分类法" aria-label="Permalink to &quot;分类法&quot;">​</a></h3><p>全书按疾病分类，共1104门，涉及：</p><ul><li>内科（伤寒、温病、杂病等）</li><li>外科（痈疽、疮肿、金疮等）</li><li>妇科（经带胎产）</li><li>儿科（小儿诸病）</li><li>五官科（眼、耳、鼻、喉）</li><li>针灸</li><li>解毒</li></ul><h3 id="特色内容" tabindex="-1">特色内容 <a class="header-anchor" href="#特色内容" aria-label="Permalink to &quot;特色内容&quot;">​</a></h3><ul><li><strong>伤寒</strong>：汇集《伤寒论》各家注（如王叔和、孙思邈等人的注解）</li><li><strong>温病</strong>：对温病的认识比《千金方》更系统</li><li><strong>眼科</strong>：有专门的眼科卷，是唐代最丰富的眼科文献</li><li><strong>矿物药</strong>：详论炼丹和矿物药的使用</li></ul><hr><h2 id="三、经典名言" tabindex="-1">三、经典名言 <a class="header-anchor" href="#三、经典名言" aria-label="Permalink to &quot;三、经典名言&quot;">​</a></h2><blockquote><p><strong>「凡疗病，必先诊脉，知病所在，乃可攻之。」</strong></p></blockquote><blockquote><p><strong>「医者意也，须识变通。」</strong></p></blockquote><hr><h2 id="四、对后世的影响" tabindex="-1">四、对后世的影响 <a class="header-anchor" href="#四、对后世的影响" aria-label="Permalink to &quot;四、对后世的影响&quot;">​</a></h2><ul><li>宋代校正医书局将此书作为官方教材</li><li>日本《医心方》（984年）大量引用</li><li>是研究唐以前医学最重要的文献之一</li></ul><hr><p><em>本条目为精简框架版。</em></p>',23)])])}const g=t(e,[["render",i]]);export{_ as __pageData,g as default};
